function solve(arr: (string|number)[]): Record<string, number> {
  const m = new Map<string, number>();
  for (const x of arr) {
    const k = String(x);
    m.set(k, (m.get(k) || 0) + 1);
  }
  return Object.fromEntries(m.entries());
}

snippets.C0016:
// NestJS (Node Framework) · 11.0.0
// Caso: Top-K frecuentes | Nivel: Intermedio | Categoría: Map/Hash

function solve(arr: (string|number)[], k: number): string[] {
  const freq = new Map<string, number>();
  for (const x of arr) {
    const key = String(x);
    freq.set(key, (freq.get(key) || 0) + 1);
  }
  return [...freq.entries()].sort((a,b)=>b[1]-a[1]).slice(0,k).map(([v])=>v);
}

snippets.C0017:
// NestJS (Node Framework) · 11.0.0
// Caso: Two Sum | Nivel: Intermedio | Categoría: Map/Hash

function solve(arr: number[], target: number): [number, number] | null {
  const seen = new Map<number, number>();
  for (let i=0;i<arr.length;i++) {
    const need = target - arr[i];
    if (seen.has(need)) return [seen.get(need)!, i];
    seen.set(arr[i], i);
  }
  return null;
}

