// Caso: Rotar arreglo k | Nivel: Intermedio | Categoría: Arrays

function solve(arr: number[], k: number): number[] {
  const n = arr.length;
  if (n === 0) return [];
  const r = ((k % n) + n) % n;
  return arr.slice(-r).concat(arr.slice(0, n - r));
}

