snippets.C0021:
// NestJS (Node Framework) · 11.0.0
// Caso: Búsqueda binaria | Nivel: Intermedio | Categoría: Búsqueda

function solve(arr: number[], target: number): number {
  let lo=0, hi=arr.length-1;
  while (lo<=hi) {
    const mid = Math.floor((lo+hi)/2);
    if (arr[mid]===target) return mid;
    if (arr[mid]<target) lo=mid+1; else hi=mid-1;
  }
  return -1;
}

snippets.C0022:
// NestJS (Node Framework) · 11.0.0
// Caso: Bubble sort | Nivel: Intermedio | Categoría: Ordenamiento

function solve(arr: number[]): number[] {
  const a = arr.slice();
  for (let i=0;i<a.length;i++) {
    for (let j=0;j<a.length-1-i;j++) {
      if (a[j] > a[j+1]) { const t=a[j]; a[j]=a[j+1]; a[j+1]=t; }
    }
  }
  return a;
}

