// NestJS (Node Framework) · 11.0.0
// Caso: Bubble sort (caso #1) | Nivel: Intermedio | Categoría: Arrays

function solve(arr: number[]): number[] {
  const a = arr.slice();
  for (let i=0;i<a.length;i++) {
    for (let j=0;j<a.length-1-i;j++) {
      if (a[j] > a[j+1]) { const t=a[j]; a[j]=a[j+1]; a[j+1]=t; }
    }
  }
  return a;
}

