// Caso: Two Sum (caso #3) | Nivel: Intermedio | Categoría: Map/Hash

function solve(arr: number[], target: number): [number, number] | null {
  const seen = new Map<number, number>();
  for (let i=0;i<arr.length;i++) {
    const need = target - arr[i];
    if (seen.has(need)) return [seen.get(need)!, i];
    seen.set(arr[i], i);
  }
  return null;
}

