// NestJS (Node Framework) · 11.0.0
// Caso: Top-K frecuentes (caso #8) | Nivel: Intermedio | Categoría: Map/Hash

function solve(arr: (string|number)[], k: number): string[] {
  const freq = new Map<string, number>();
  for (const x of arr) {
    const key = String(x);
    freq.set(key, (freq.get(key) || 0) + 1);
  }
  return [...freq.entries()].sort((a,b)=>b[1]-a[1]).slice(0,k).map(([v])=>v);
}

