export async function solve(offset = 20, limit = 10): Promise<User[]> {
  const db = await openDb(1);
  const tx = db.transaction(['users'], 'readonly');
  const store = tx.objectStore('users');
  const out: User[] = [];
  let skipped = 0;
  await new Promise<void>((resolve, reject) => {
    const r = store.openCursor();
    r.onsuccess = () => {
      const cur = r.result;
      if (!cur) return resolve();
      if (skipped < offset) { skipped++; cur.continue(); return; }
      if (out.length >= limit) return resolve();
      out.push(cur.value as User);
      cur.continue();
