// NestJS (Node Framework) · 11.0.0
// C0650 · Leer/Escribir CSV (UTF-8) (Intermedio, IO)
// Browser · PapaParse (CSV)
// <script src="https://cdn.jsdelivr.net/npm/papaparse@5.4.1/papaparse.min.js"></script>
// Lee input.csv desde un <input type="file"> y descarga output.csv
function solve(file) {
  return new Promise((resolve, reject) => {
    Papa.parse(file, {
      header: true,
      skipEmptyLines: true,
      complete: (res) => {
        const rows = res.data.map(r => ({
          ...r,
          Email: r.Email ? String(r.Email).trim().toLowerCase() : r.Email
        }));
        const outCsv = Papa.unparse(rows, { quotes: false });
        const blob = new Blob([outCsv], { type: "text/csv;charset=utf-8" });
        const a = document.createElement("a");
        a.href = URL.createObjectURL(blob);
        a.download = "output.csv";
        a.click();
        resolve(rows.length);
      },
      error: (err) => reject(err),
    });
  });
}

