async function solve() {
  const secret = new TextEncoder().encode("supersecret");
  const jwt = await jose.SignJWT({ sub: "123" })
    .setProtectedHeader({ alg: "HS256" })
    .setIssuedAt()
    .setExpirationTime("2h")
