// NestJS (Node Framework) · 11.0.0
// C0668 · A* (pathfinding) (Avanzado, Algoritmos)
// A* en grilla 2D (4-direcciones)
function solve(grid, start, goal){
  const h = (a,b)=>Math.abs(a[0]-b[0])+Math.abs(a[1]-b[1]);
  const key = (p)=>p[0]+","+p[1];
  const W=grid[0].length, H=grid.length;

  function neighbors(p){
    const [x,y]=p;
    const out=[];
    for(const [dx,dy] of [[1,0],[-1,0],[0,1],[0,-1]]){
      const nx=x+dx, ny=y+dy;
      if(nx>=0 && ny>=0 && nx<W && ny<H && grid[ny][nx]===0) out.push([nx,ny]);
    }
    return out;
  }

  const open=[{p:start, f:h(start,goal)}];
  const came=new Map();
  const g=new Map([[key(start),0]]);

  while(open.length){
    open.sort((a,b)=>a.f-b.f);
    const cur = open.shift().p;
    if(cur[0]===goal[0] && cur[1]===goal[1]){
      const path=[cur];
      let ck=key(cur);
      while(came.has(ck)){
        const prev=came.get(ck);
        path.push(prev);
        ck=key(prev);
      }
      return path.reverse();
    }
    for(const nb of neighbors(cur)){
      const nk=key(nb);
      const ng=g.get(key(cur))+1;
      if(!g.has(nk) || ng<g.get(nk)){
        g.set(nk,ng);
        came.set(nk,cur);
        open.push({p:nb, f:ng+h(nb,goal)});
      }
    }
  }
  return [];
}

