// C0684 · REST CRUD JSON (GET/POST/PUT/DELETE)
import { Body, Controller, Delete, Get, Param, Post, Put } from "@nestjs/common";
let items: any[] = []; let seq = 1;

@Controller("items")
export class ItemsController {
  @Get() list(){ return items; }
  @Post() create(@Body() body:any){
    const it = { id: seq++, name: String(body?.name||"") };
    items.push(it); return it;
  }
  @Put(":id") update(@Param("id") id:string, @Body() body:any){
    const idx = items.findIndex(x=>x.id===Number(id));
    if(idx<0) return { error:"not_found" };
    items[idx] = { id: Number(id), name: String(body?.name||"") };
    return items[idx];
  }
  @Delete(":id") del(@Param("id") id:string){
    items = items.filter(x=>x.id!==Number(id));
    return { ok:true };
  }
}

